func TestDeliverFileIgnoresPredictableTempSymlink(t *testing.T) {
	dir := t.TempDir()
	target := filepath.Join(dir, "result.json")
	victim := filepath.Join(dir, "victim.txt")
	if err := os.WriteFile(victim, []byte("safe"), 0o600); err != nil {
		t.Fatal(err)
	}
	if err := os.Symlink(victim, target+".tmp"); err != nil {
		t.Fatal(err)
	}
	if err := deliverFile(target, []byte("delivered")); err != nil {
		t.Fatal(err)
	}
	got, err := os.ReadFile(victim)
	if err != nil {
		t.Fatal(err)
	}
	if string(got) != "safe" {
		t.Fatalf("predictable temp symlink target was overwritten: %q", got)
	}
	got, err = os.ReadFile(target)
	if err != nil || string(got) != "delivered" {
		t.Fatalf("delivered target = %q, err = %v", got, err)
	}
	info, err := os.Stat(target)
	if err != nil {
		t.Fatal(err)
	}
	if info.Mode().Perm() != 0o600 {
		t.Fatalf("delivered mode = %o, want 600", info.Mode().Perm())
	}
}
